// Merge and deduplicate RSS items from all feeds
const allItems = $input.all();
const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);

const seen = new Set();
const articles = [];

for (const item of allItems) {
  const j = item.json;
  const title = (j.title || '').trim();
  if (!title || seen.has(title.toLowerCase())) continue;

  const pubDate = new Date(j.pubDate || j.isoDate || 0);
  if (pubDate < sevenDaysAgo) continue;

  seen.add(title.toLowerCase());
  articles.push({
    title,
    link: j.link || '',
    summary: (j.contentSnippet || j.summary || '').substring(0, 400),
    pubDate: pubDate.toLocaleDateString('en-US'),
    source: j.feedUrl?.includes('techcrunch') ? 'TechCrunch' : j.feedUrl?.includes('venturebeat') ? 'VentureBeat' : 'AI News'
  });
}

// Sort by date, take top 10
const top10 = articles.slice(0, 10);

const articlesList = top10.map((a, i) =>
  `${i + 1}. [${a.source}] ${a.title}\nURL: ${a.link}\nSummary: ${a.summary}\n`
).join('\n');

return [{ json: { articles: top10, articlesList, count: top10.length } }];

