const rawContent = $input.first().json.message?.content || '{}';
let newsletter;
try {
  newsletter = JSON.parse(rawContent);
} catch (e) {
  // If not valid JSON, treat as raw HTML
  newsletter = { subject: 'The AI Stack Weekly — Week of ' + new Date().toLocaleDateString(), html: rawContent };
}

return [{
  json: {
    subject: newsletter.subject || 'The AI Stack Weekly',
    htmlBody: newsletter.html || rawContent,
    draftedAt: new Date().toISOString()
  }
}];

